/**
 * Email Verification Success Page
 * 
 * Displays success confirmation after email verification. Processes
 * verification token and shows success message before redirecting to login.
 */

import React, { useEffect, useRef, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services';
import { LanguageSelector } from '@/shared/components';
import logger from '@/shared/utils/logger.js';
import '/styles/index.css';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

const EmailVerificationSuccess = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { success } = useToast();
  const { effectiveTheme } = useTheme();
  const hasVerifiedRef = useRef(false); // Prevent multiple calls
  const isVerifyingRef = useRef(false); // Prevent simultaneous calls

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  // Extract and normalize parameters from URL (same logic as VerifyEmailPage)
  const normalizedParams = useMemo(() => {
    const raw = window.location.search || '';
    const fixed = raw.replace(/(token=[^&?#]+)\?/, '$1&');
    const sp = new URLSearchParams(fixed);
    // URLSearchParams automatically decodes the token, but ensure it's trimmed
    let token = (sp.get('token') || '').trim();
    // If token appears to be URL-encoded, decode it (though URLSearchParams should handle this)
    if (token && token.includes('%')) {
      try {
        token = decodeURIComponent(token);
      } catch (e) {
        logger.warn('Failed to decode token', { error: e });
      }
    }
    const usertype = (sp.get('usertype') || '').toLowerCase();
    logger.debug('EmailVerificationSuccessPage: Extracted from URL', {
      tokenLength: token.length,
      tokenPreview: token.substring(0, 30) + '...',
      usertype
    });
    return { token, usertype };
  }, [searchParams]);

  const { token, usertype } = normalizedParams;

  useEffect(() => {
    // Prevent multiple calls - if no token, already verified, or currently verifying, return early
    if (!token || hasVerifiedRef.current || isVerifyingRef.current) {
      logger.debug('EmailVerificationSuccessPage: Skipping verification', {
        hasToken: !!token,
        hasVerified: hasVerifiedRef.current,
        isVerifying: isVerifyingRef.current
      });
      return;
    }

    // Validate usertype
    if (!['customer', 'business_contact'].includes(usertype)) {
      logger.warn('EmailVerificationSuccessPage: Invalid usertype from URL', { usertype });
      return;
    }

    // Mark as verifying to prevent duplicate calls
    isVerifyingRef.current = true;

    const verifyEmail = async () => {
      try {
        logger.debug('EmailVerificationSuccessPage: Calling verifyEmail API (first call)', {
          token: token ? `${token.substring(0, 20)}...` : 'none',
          usertype,
          endpoint: '/api/publicauth/verify-email',
          payload: { token, usertype }
        });

        // First API call
        const firstResult = await authService.verifyEmail(token, usertype);
        logger.debug('EmailVerificationSuccessPage: First API response received', {
          success: firstResult.success,
          message: firstResult.message
        });

        // Second API call
        logger.debug('EmailVerificationSuccessPage: Calling verifyEmail API (second call)', {
          token: token ? `${token.substring(0, 20)}...` : 'none',
          usertype,
          payload: { token, usertype }
        });
        const secondResult = await authService.verifyEmail(token, usertype);
        logger.debug('EmailVerificationSuccessPage: Second API response received', {
          success: secondResult.success,
          message: secondResult.message
        });

        // Use the result from the second call (or first if second failed)
        const finalResult = secondResult.success ? secondResult : firstResult;

        if (finalResult.success) {
          hasVerifiedRef.current = true; // Mark as verified to prevent future calls
          success(finalResult.message || t('emailVerificationSuccess', { ns: 'auth' }) + '! ' + t('emailVerifiedCanSignIn', { ns: 'auth' }));
        } else {
          throw new Error(finalResult.message || t('emailVerificationFailed', { ns: 'auth' }));
        }
      } catch (error) {
        logger.error('EmailVerificationSuccessPage: Email verification error', { error });
        if (error.message?.includes('refreshToken.delete')) {
          hasVerifiedRef.current = true; // Mark as verified even if cleanup failed
          success(t('emailVerificationSuccess', { ns: 'auth' }) + '! ' + t('emailVerifiedCanSignIn', { ns: 'auth' }));
        } else {
          logger.error('Verification error', { error: error.message });
          isVerifyingRef.current = false; // Reset on error so user can retry if needed
        }
      } finally {
        isVerifyingRef.current = false; // Reset verifying flag
      }
    };

    verifyEmail();
  }, [normalizedParams.token, normalizedParams.usertype, t, success]); // Use normalizedParams

  return (
    <div className="login-container">
      <div className="login-form" style={{ position: 'relative' }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1
          }}
        />

        <h2 style={{ color: '#16a34a', marginBottom: '16px' }}>{t('emailVerifiedSuccessfully', { ns: 'auth' })}</h2>

        <div style={{
          backgroundColor: '#f0fdf4',
          border: '1px solid #bbf7d0',
          borderRadius: '8px',
          padding: '16px',
          marginBottom: '20px',
          textAlign: 'center',
          color: '#16a34a'
        }}>
          <div style={{
            width: '48px',
            height: '48px',
            backgroundColor: '#16a34a',
            borderRadius: '50%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 12px',
            color: 'white',
            fontSize: '24px'
          }}>
            ✓
          </div>
          <p style={{ margin: 0, fontWeight: '600' }}>
            {t('emailVerificationSuccess', { ns: 'auth' })}
          </p>
          <p style={{ margin: '8px 0 0 0', fontSize: '14px', color: '#15803d' }}>
            {t('emailVerifiedAccessFeatures', { ns: 'auth' })}
          </p>
        </div>

        <button
          onClick={() => navigate('/login')}
          style={{ width: '100%', marginBottom: '16px' }}
        >
          {t('goToLogin', { ns: 'auth' })}
        </button>

        <div style={{ display: 'flex', gap: '8px' }}>
          <button
            type="button"
            onClick={() => navigate('/user-type-selection')}
            style={{ flex: 1, backgroundColor: '#6b7280' }}
          >
            {t('backToRegister', { ns: 'auth' })}
          </button>
        </div>
      </div>
    </div>
  );
};

export default EmailVerificationSuccess;
